import { authHandler } from "encore.dev/auth";
import { Unauthenticated } from "encore.dev/errors";

export interface AuthData {
  userID: string;
}

export const auth = authHandler<AuthData>(async (token) => {
  if (!token) {
    throw new Unauthenticated("missing authorization token");
  }

  if (token !== "secret-token") {
    throw new Unauthenticated("invalid authorization token");
  }

  return { userID: "user-123" };
});

import { api } from "encore.dev/api";
import type { AuthData } from "./auth";

interface DashboardResponse {
  message: string;
}

export const dashboard = api<never, DashboardResponse>(
  { method: "GET", path: "/dashboard", auth: true },
  async (_req, ctx) => {
    const auth = ctx.auth as AuthData;
    return { message: `Welcome to the dashboard, ${auth.userID}!` };
  }
);
